class Solution {
    public int[] memLeak(int memory1, int memory2) {
        int crashTime = 1;
        int memory1Crash = 0;
        int memory2Crash = 0;
        while (true) {
            if (memory1 >= crashTime && memory2 >= crashTime) {
                memory1 -= crashTime;
                memory2 -= crashTime;
                crashTime++;
            } else if (memory1 >= crashTime) {
                memory1 -= crashTime;
                memory1Crash = crashTime - 1;
                break;
            } else {
                memory2 -= crashTime;
                memory2Crash = crashTime - 1;
                break;
            }
        }
        return new int[]{crashTime - 1, memory1Crash, memory2Crash};
    }
}

